function RizqQuote({page}){const q=RIZQ_QUOTES[page];if(!q)return null;return<div style={{background:'rgba(107,127,94,0.06)',border:'1px solid rgba(107,127,94,0.15)',borderRadius:10,padding:'12px 16px',marginBottom:24,textAlign:'center'}}>{q.ar&&<div style={{fontFamily:"'Noto Sans Arabic', serif",fontSize:16,color:T.accent,marginBottom:6,lineHeight:1.8,direction:'rtl'}}>{q.ar}</div>}<div style={{fontSize:12,color:T.textSecondary,fontStyle:'italic',lineHeight:1.5}}>{q.en}</div></div>;}

function getBillingPeriods(dispatches,expenses){const allDates=[...dispatches.map(d=>new Date(d.dispatched_at)),...(expenses||[]).map(e=>new Date(e.expense_date))];if(!allDates.length)return[];const minDate=new Date(Math.min(...allDates));const maxDate=new Date(Math.max(...allDates));const periods=[];let start=new Date(minDate.getFullYear(),minDate.getMonth(),8);if(minDate.getDate()<8)start.setMonth(start.getMonth()-1);while(start<=maxDate){const end=new Date(start.getFullYear(),start.getMonth()+1,7);periods.push({label:`${start.toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})} – ${end.toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}`,start:new Date(start),end:new Date(end.getFullYear(),end.getMonth(),end.getDate(),23,59,59)});start=new Date(start.getFullYear(),start.getMonth()+1,8);}return periods;}

function getAvailableStock(procurements){
  const m={};for(const p of procurements){if(p.remaining_qty<=0)continue;const k=`${p.category_id}|${p.brand_id}`;if(!m[k])m[k]={category_id:p.category_id,brand_id:p.brand_id,totalQty:0,totalCostVal:0};m[k].totalQty+=p.remaining_qty;m[k].totalCostVal+=p.remaining_qty*parseFloat(p.unit_price_gbp);}
  for(const k in m)m[k].avgCost=m[k].totalCostVal/m[k].totalQty;return Object.values(m);
}

